/* IfWcsInboundMapper.selectSibwcsOrderType - WCS적치 오더유형 조회 */
SELECT SIBWCS.ORDER_TYPE
  FROM TWORK_INTF_SIBWCS SIBWCS
 WHERE SIBWCS.IB_SEQ = #{ibSeq}

mapper.update:
/* IfWcsInboundMapper.updateInterfaceStatus - WCS입고주문 상태변경 TEST 조회 */
UPDATE TWORK_INTF_SIBWCS
   SET SUCCEEDED = 'false'
   	 , IB_NUMBER = '*' || IB_NUMBER
 WHERE IB_SEQ = #{IB_SEQ}
